// ============================================================
// Por cada lead nuevo (modelo nuevo de la auditoría, sección 14):
//   1. Crea UNA oportunidad "Por diagnosticar" (no una por
//      aseguradora: eso distorsionaba pipeline y métricas).
//   2. Crea N cotizaciones "Pendiente" anidadas, una por
//      aseguradora sugerida según el producto, con su link.
//   3. Avisa al asesor por WhatsApp (CallMeBot).
//   4. Marca el lead como procesado (n8n_procesado).
// Si un lead falla a mitad, NO se marca procesado: se reintenta
// en el siguiente ciclo (los inserts duplicados posibles son
// visibles y borrables desde Ventas).
// ============================================================
const config = $('Config').first().json;

const PLAN = {
  'Auto':           ['AXA', 'HDI', 'ABA Seguros', 'GNP'],
  'Vida':           ['GNP', 'MetLife', 'AXA'],
  'Gastos Médicos': ['GNP', 'AXA', 'MetLife'],
  'Hogar':          ['AXA', 'HDI', 'GNP'],
  'Retiro':         ['Profuturo', 'MetLife'],
  'Empresas':       ['GNP', 'MetLife', 'AXA'],
  'Referido':       ['GNP', 'AXA']
};

const URLS = {
  'AXA': 'https://axa.mx/',
  'HDI': 'https://www.hdi.com.mx/personas/seguros-autos/',
  'ABA Seguros': 'https://miauto.com.mx/seguros/aba',
  'GNP': 'https://www.gnp.com.mx/',
  'MetLife': 'https://www.metlife.com.mx/',
  'Profuturo': 'https://www.profuturo.mx/'
};

const headers = {
  apikey: config.service_key,
  Authorization: `Bearer ${config.service_key}`,
  'Content-Type': 'application/json',
};

const salida = [];
for (const item of $input.all()) {
  const p = item.json;
  if (!p || !p.id) continue;
  const producto = p.producto || 'Referido';
  const aseguradoras = PLAN[producto] || PLAN['Referido'];

  try {
    // 0. IDEMPOTENCIA: si un intento anterior ya creó la oportunidad
    //    (y falló después, p.ej. en el WhatsApp), se reutiliza en vez
    //    de duplicar. El reintento es seguro.
    const existentes = await this.helpers.httpRequest({
      method: 'GET',
      url: `${config.supabase_url}/rest/v1/oportunidades?prospecto_id=eq.${p.id}&select=id&limit=1`,
      headers,
      json: true,
    });
    let oportunidadId;
    let creadaAhora = false;

    if (Array.isArray(existentes) && existentes.length > 0) {
      oportunidadId = existentes[0].id;
    } else {
      // 1. UNA oportunidad por lead
      const ops = await this.helpers.httpRequest({
        method: 'POST',
        url: `${config.supabase_url}/rest/v1/oportunidades`,
        headers: { ...headers, Prefer: 'return=representation' },
        body: [{
          cliente: p.nombre,
          producto: producto === 'Referido' ? 'Por definir' : producto,
          estado: 'Por diagnosticar',
          prospecto_id: p.id,
          user_id: p.user_id,
        }],
        json: true,
      });
      oportunidadId = Array.isArray(ops) ? ops[0].id : ops.id;
      creadaAhora = true;
    }

    // 2. Cotizaciones pendientes por aseguradora (anidadas).
    //    IDEMPOTENCIA: solo si la oportunidad aún no tiene ninguna.
    const cotsExistentes = await this.helpers.httpRequest({
      method: 'GET',
      url: `${config.supabase_url}/rest/v1/cotizaciones?oportunidad_id=eq.${oportunidadId}&select=id&limit=1`,
      headers,
      json: true,
    });
    if (!Array.isArray(cotsExistentes) || cotsExistentes.length === 0) {
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${config.supabase_url}/rest/v1/cotizaciones`,
        headers: { ...headers, Prefer: 'return=minimal' },
        body: aseguradoras.map(a => ({
          oportunidad_id: oportunidadId,
          aseguradora: a,
          estado: 'Pendiente',
          url_cotizador: URLS[a] || null,
          user_id: p.user_id,
        })),
        json: true,
      });
    }

    // 3. Línea de tiempo: solo si la oportunidad se creó en este intento
    //    (un reintento no duplica la actividad).
    if (creadaAhora) await this.helpers.httpRequest({
      method: 'POST',
      url: `${config.supabase_url}/rest/v1/actividades`,
      headers: { ...headers, Prefer: 'return=minimal' },
      body: [{
        user_id: p.user_id,
        prospecto_id: p.id,
        oportunidad_id: oportunidadId,
        tipo: 'oportunidad_creada',
        descripcion: `Automático (n8n): oportunidad ${producto === 'Referido' ? 'Por definir' : producto} con ${aseguradoras.length} cotizaciones pendientes`,
      }],
      json: true,
    });

    // 4. Aviso por WhatsApp
    const links = aseguradoras.map(a => `${a}: ${URLS[a] || ''}`).join('\n');
    const mensaje =
      `NUEVO LEAD (${producto})\n` +
      `Nombre: ${p.nombre}\n` +
      `WhatsApp: ${p.telefono}\n` +
      `Datos: ${p.nota_entrada_web || 'sin detalles'}\n\n` +
      `Se creó 1 oportunidad con ${aseguradoras.length} cotizaciones pendientes.\n` +
      `Cotizar en:\n${links}`;
    await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.callmebot.com/whatsapp.php',
      qs: {
        phone: config.whatsapp_phone,
        text: mensaje,
        apikey: config.callmebot_apikey,
      },
    });

    // 5. Marcar procesado (solo si todo lo anterior funcionó)
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${config.supabase_url}/rest/v1/prospectos?id=eq.${p.id}`,
      headers: { ...headers, Prefer: 'return=minimal' },
      body: { n8n_procesado: new Date().toISOString() },
      json: true,
    });

    salida.push({ json: { lead: p.id, ok: true, oportunidad: oportunidadId, cotizaciones: aseguradoras.length } });
  } catch (e) {
    salida.push({ json: { lead: p.id, ok: false, error: String(e && e.message || e) } });
  }
}

return salida.length ? salida : [{ json: { ok: true, mensaje: 'Sin leads pendientes' } }];
